// Fungsi untuk menggabungkan alias (tanpa duplikasi)
function extendDict(dict, additions, aliases) {
    for (const [key, aliasList] of Object.entries(additions)) {
        if (!dict[key]) dict[key] = [];
        dict[key] = [...new Set([...dict[key], ...aliasList])];
    }
    for (const [key, aliasList] of Object.entries(aliases)) {
        if (!dict[key]) dict[key] = [];
        dict[key] = [...new Set([...dict[key], ...aliasList])];
    }
    return dict;
}

